import type { ComponentType, ReactNode, SVGAttributes } from 'react';

export type BimIconHifiProps = SVGAttributes<SVGSVGElement> & {
  size?: number | string;
};

export type BimIconProps = SVGAttributes<SVGSVGElement> & {
  size?: number | string;
  strokeWidth?: number | string;
  absoluteStrokeWidth?: boolean;
};

export type BimIcon = ComponentType<BimIconProps>;

/**
 * Creates a BIM icon component from a static ReactNode of SVG children.
 * The returned component has the same props API as lucide-react icons:
 * `size`, `strokeWidth`, `absoluteStrokeWidth`, plus any SVG attribute.
 *
 * All icons are 24×24 viewBox, stroke-based with currentColor. Default
 * strokeWidth is 1.5; active/selected state uses 2.0 (driven by the parent).
 */
export function bimIcon(displayName: string, paths: ReactNode): BimIcon {
  function Icon({ size = 24, strokeWidth = 1.5, absoluteStrokeWidth, ...rest }: BimIconProps) {
    const sw = absoluteStrokeWidth ? (Number(strokeWidth) * 24) / Number(size) : strokeWidth;
    return (
      <svg
        xmlns="http://www.w3.org/2000/svg"
        width={size}
        height={size}
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth={sw}
        strokeLinecap="round"
        strokeLinejoin="round"
        aria-hidden="true"
        focusable="false"
        {...rest}
      >
        {paths}
      </svg>
    );
  }
  Icon.displayName = displayName;
  return Icon;
}

/**
 * Creates a high-fidelity BIM icon at 48×48 viewBox.
 *
 * Unlike bimIcon, children fully control their own fill and stroke —
 * the SVG root only provides `stroke="currentColor"` and `fill="none"` as
 * defaults, which individual elements can override with explicit attributes
 * (e.g. `fill="currentColor" fillOpacity={0.08}` for material fills).
 *
 * Stroke hierarchy convention:
 *   strokeWidth 2   — primary faces / outlines
 *   strokeWidth 1.5 — secondary edges / reveals
 *   strokeWidth 0.75 — material hatch, detail lines
 */
export function bimIconHifi(
  displayName: string,
  paths: ReactNode,
): ComponentType<BimIconHifiProps> {
  function Icon({ size = 48, ...rest }: BimIconHifiProps) {
    return (
      <svg
        xmlns="http://www.w3.org/2000/svg"
        width={size}
        height={size}
        viewBox="0 0 48 48"
        fill="none"
        stroke="currentColor"
        strokeLinecap="round"
        strokeLinejoin="round"
        aria-hidden="true"
        focusable="false"
        {...rest}
      >
        {paths}
      </svg>
    );
  }
  Icon.displayName = displayName;
  return Icon;
}

import { BrowserRouter, Route, Routes } from 'react-router';
import { Workspace } from './workspace/Workspace';
import { IconGallery } from './design-systems/IconGallery';
import { FamilyEditorWorkbench } from './familyEditor/FamilyEditorWorkbench';

export function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Workspace />} />
        <Route path="/icons" element={<IconGallery />} />
        <Route path="/family-editor" element={<FamilyEditorWorkbench />} />
      </Routes>
    </BrowserRouter>
  );
}

/**
 * High-fidelity 48×48 BIM icons.
 *
 * Designed for display contexts (empty states, library tiles, mode splash areas)
 * where a 48px render size rewards material hatching, fills, and architectural detail.
 *
 * Color scheme — all fills are driven by CSS custom properties so callers can
 * switch between variants by setting variables on a wrapper element:
 *
 *   --hi-concrete / --hi-concrete-op  (walls, columns, slabs, stair treads)
 *   --hi-glass    / --hi-glass-op     (glazing panes)
 *   --hi-steel    / --hi-steel-op     (I-beam sections)
 *   --hi-leaf                          (door leaf panel)
 *   --hi-roof     / --hi-roof-op      (roof surface)
 *   --hi-room     / --hi-room-op      (room interior fill)
 *
 * When the variables are not set the icons render in a tasteful monochrome
 * using currentColor at low opacity (default behaviour, theme-adaptive).
 *
 * Stroke hierarchy:
 *   strokeWidth 2    — primary faces / main outlines
 *   strokeWidth 1.5  — secondary edges, reveals, jambs
 *   strokeWidth 0.75 — hatch lines, detail lines
 */
import { bimIconHifi } from './icon';

// ── Wall: plan cross-section with concrete hatch ──────────────────────────────
export const WallHifi = bimIconHifi(
  'WallHifi',
  <>
    <rect
      x="4"
      y="18"
      width="40"
      height="12"
      style={{
        fill: 'var(--hi-concrete, currentColor)',
        fillOpacity: 'var(--hi-concrete-op, 0.07)',
      }}
    />
    <g strokeWidth={0.75} strokeOpacity={0.4}>
      <line x1="4" y1="24" x2="10" y2="18" />
      <line x1="4" y1="30" x2="16" y2="18" />
      <line x1="10" y1="30" x2="22" y2="18" />
      <line x1="16" y1="30" x2="28" y2="18" />
      <line x1="22" y1="30" x2="34" y2="18" />
      <line x1="28" y1="30" x2="40" y2="18" />
      <line x1="34" y1="30" x2="44" y2="20" />
      <line x1="40" y1="30" x2="44" y2="26" />
    </g>
